const fs = require('fs');
const path = require('path');
const vaultPath = 'C:/Users/manaz/Desktop/JobFilter/JobFilterV1/Obsidian_Memory/Obsidian_Vault';
const snap = path.join(vaultPath, 'JobFilter', 'Agent Runs', '.competitor-watch-prev.json');
const allResults = $input.first().json.data || [];
const current = {};
for (const r of allResults) {
  if (!r.ok) continue;
  current[r.outward || 'unknown'] = (r.leads || []).map(l => ({ id: l.id, title: l.title, score: l.score, source: l.source }));
}
let prev = {};
if (fs.existsSync(snap)) { try { prev = JSON.parse(fs.readFileSync(snap, 'utf-8')); } catch {} }
const movement = {};
for (const out of Object.keys(current)) {
  const curIds = new Set(current[out].map(l => l.id).filter(Boolean));
  const prevIds = new Set((prev[out] || []).map(l => l.id).filter(Boolean));
  const added = [...curIds].filter(id => !prevIds.has(id));
  const removed = [...prevIds].filter(id => !curIds.has(id));
  movement[out] = { now: curIds.size, then: prevIds.size, added: added.length, removed: removed.length, addedIds: added.slice(0, 10), removedIds: removed.slice(0, 10) };
}
fs.mkdirSync(path.dirname(snap), { recursive: true });
fs.writeFileSync(snap, JSON.stringify(current, null, 2));
const now = new Date();
const dateStr = now.toISOString().slice(0,10);
const intelDir = path.join(vaultPath, 'JobFilter', 'Intel');
fs.mkdirSync(intelDir, { recursive: true });
const file = path.join(intelDir, 'competitor-watch-' + dateStr + '.md');
const rows = Object.entries(movement).map(([k, v]) => `| ${k} | ${v.now} | ${v.then} | +${v.added} | -${v.removed} |`).join('\n');
const md = `---\ntype: competitor-watch\nrun_at: ${now.toISOString()}\nfor_date: ${dateStr}\ntags: [jobfilter, intel, competitor]\n---\n\n# Competitor Watch — ${dateStr}\n\n| Outward | Now | Last week | Added | Removed |\n|---------|-----|-----------|-------|---------|\n${rows}\n\n## Raw movement\n\n\`\`\`json\n${JSON.stringify(movement, null, 2)}\n\`\`\`\n`;
fs.writeFileSync(file, md);
return [{ json: { file, movement, postcodeCount: Object.keys(current).length } }];
